import { render, screen, fireEvent, waitFor } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import App from './App';

// Mock Worker
class MockWorker {
  onmessage: ((e: MessageEvent) => void) | null = null;
  onerror: ((e: ErrorEvent) => void) | null = null;
  postMessage(data: any) {
    // Simulate async worker response
    setTimeout(() => {
      if (this.onmessage) {
        this.onmessage(new MessageEvent('message', {
          data: {
            mean: 5000,
            median: 5001,
            stdDev: 2886,
            min: 0.5,
            max: 9999.5,
            sorted: [0.5, 9999.5],
          }
        }));
      }
    }, 10);
  }
  terminate() {}
}

(window as any).Worker = undefined;
(window as any).URL = { createObjectURL: () => 'blob:mock', revokeObjectURL: () => {} };
(window as any).Blob = class { constructor() {} };

// Patch to use mock
const origWorker = (window as any).Worker;
beforeAll(() => {
  (window as any).Worker = MockWorker;
});
afterAll(() => {
  (window as any).Worker = origWorker;
});

describe('Web Worker Demo', () => {
  it('renders counter button', () => {
    render(<App />);
    expect(screen.getByTestId('counter-btn')).toBeInTheDocument();
  });

  it('counter increments on click', () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('counter-btn'));
    expect(screen.getByTestId('counter-value')).toHaveTextContent('1');
  });

  it('renders process button', () => {
    render(<App />);
    expect(screen.getByTestId('process-btn')).toBeInTheDocument();
  });

  it('shows processing indicator when clicked', () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('process-btn'));
    expect(screen.getByTestId('processing')).toBeInTheDocument();
  });

  it('shows results after worker completes', async () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('process-btn'));
    await waitFor(() => {
      expect(screen.getByTestId('result-stats')).toBeInTheDocument();
    });
  });

  it('status updates during processing', () => {
    render(<App />);
    expect(screen.getByTestId('status')).toHaveTextContent('Idle');
    fireEvent.click(screen.getByTestId('process-btn'));
    expect(screen.getByTestId('status').textContent).not.toBe('Idle');
  });
});

