import React, { useState, useRef, useEffect, useCallback } from 'react';
import './styles.css';

interface Stats {
  mean: number;
  median: number;
  stdDev: number;
  min: number;
  max: number;
  sorted: number[];
}

const workerCode = `
self.onmessage = function(e) {
  try {
    var data = e.data;
    data.sort(function(a, b) { return a - b; });
    var n = data.length;
    var sum = 0;
    var min = data[0];
    var max = data[n - 1];
    for (var i = 0; i < n; i++) { sum += data[i]; }
    var mean = sum / n;
    var median = n % 2 === 0 ? (data[n / 2 - 1] + data[n / 2]) / 2 : data[Math.floor(n / 2)];
    var sqDiffSum = 0;
    for (var j = 0; j < n; j++) { sqDiffSum += (data[j] - mean) * (data[j] - mean); }
    var stdDev = Math.sqrt(sqDiffSum / n);
    self.postMessage({ mean: mean, median: median, stdDev: stdDev, min: min, max: max, sorted: data.slice(0, 10) });
  } catch (err) {
    self.postMessage({ error: err.message || 'Worker error' });
  }
};
`;

export const WorkerDemo: React.FC = () => {
  const [counter, setCounter] = useState(0);
  const [isProcessing, setIsProcessing] = useState(false);
  const [stats, setStats] = useState<Stats | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [status, setStatus] = useState('Idle');
  const workerRef = useRef<Worker | null>(null);
  const blobUrlRef = useRef<string | null>(null);

  useEffect(() => {
    const blob = new Blob([workerCode], { type: 'application/javascript' });
    const url = URL.createObjectURL(blob);
    blobUrlRef.current = url;
    const worker = new Worker(url);
    workerRef.current = worker;

    worker.onmessage = (e: MessageEvent) => {
      if (e.data.error) {
        setError(e.data.error);
        setStatus('Error');
      } else {
        setStats(e.data);
        setStatus('Complete');
      }
      setIsProcessing(false);
    };

    worker.onerror = () => {
      setError('Worker encountered an error');
      setIsProcessing(false);
      setStatus('Error');
    };

    return () => {
      worker.terminate();
      if (blobUrlRef.current) URL.revokeObjectURL(blobUrlRef.current);
    };
  }, []);

  const generateData = useCallback(() => {
    return Array.from({ length: 100000 }, () => Math.random() * 10000);
  }, []);

  const handleProcess = useCallback(() => {
    setIsProcessing(true);
    setError(null);
    setStats(null);
    setStatus('Processing…');
    const data = generateData();
    workerRef.current?.postMessage(data);
  }, [generateData]);

  return (
    <div className="worker">
      <div className="worker__section">
        <h2>Main Thread Test</h2>
        <p className="worker__hint">Click the counter while processing — it should stay responsive</p>
        <button data-testid="counter-btn" className="worker__btn" onClick={() => setCounter(c => c + 1)}>
          Count: <span data-testid="counter-value">{counter}</span>
        </button>
      </div>

      <div className="worker__section">
        <h2>Worker Computation</h2>
        <button
          data-testid="process-btn"
          className="worker__btn worker__btn--primary"
          onClick={handleProcess}
          disabled={isProcessing}
        >
          {isProcessing ? 'Processing…' : 'Process 100K Numbers'}
        </button>

        <p data-testid="status" className="worker__status">{status}</p>

        {isProcessing && (
          <div data-testid="processing" className="worker__processing">⏳ Computing in worker…</div>
        )}

        {error && (
          <div data-testid="error-display" className="worker__error">{error}</div>
        )}

        {stats && (
          <div data-testid="result-stats" className="worker__results">
            <div className="worker__stat">Mean: {stats.mean.toFixed(2)}</div>
            <div className="worker__stat">Median: {stats.median.toFixed(2)}</div>
            <div className="worker__stat">Std Dev: {stats.stdDev.toFixed(2)}</div>
            <div className="worker__stat">Min: {stats.min.toFixed(2)}</div>
            <div className="worker__stat">Max: {stats.max.toFixed(2)}</div>
          </div>
        )}
      </div>
    </div>
  );
};
